// Change this IP address to your phone IP shown in Phyphox Remote Access.
const PHONE_IP = "192.168.1.50";
msg.url = `http://${PHONE_IP}:8080/get?accX&accY`;
return msg;

// 2-D motion physics engine using Phyphox acceleration data
// Input: msg.payload.buffer.accX.buffer[-1], msg.payload.buffer.accY.buffer[-1]
// Output: x, y, vx, vy, speed, state, trajectory

let payload = msg.payload;

function latest(bufferObj) {
    if (!bufferObj || !bufferObj.buffer || bufferObj.buffer.length === 0) return 0;
    return Number(bufferObj.buffer[bufferObj.buffer.length - 1]);
}

let ax = latest(payload.buffer?.accX);
let ay = latest(payload.buffer?.accY);

// Noise threshold
if (Math.abs(ax) < 0.05) ax = 0;
if (Math.abs(ay) < 0.05) ay = 0;

let stateData = context.get("stateData") || {
    x: 0,
    y: 0,
    vx: 0,
    vy: 0,
    lastTime: Date.now(),
    trajectory: []
};

let now = Date.now();
let dt = (now - stateData.lastTime) / 1000.0;
stateData.lastTime = now;

// Prevent unrealistic jumps if the flow pauses
if (dt <= 0 || dt > 1.0) dt = 0.2;

// Damping reduces drift but also reduces physical accuracy
const damping = 0.98;
stateData.vx = damping * stateData.vx + ax * dt;
stateData.vy = damping * stateData.vy + ay * dt;
stateData.x = stateData.x + stateData.vx * dt;
stateData.y = stateData.y + stateData.vy * dt;

let speed = Math.sqrt(stateData.vx ** 2 + stateData.vy ** 2);
let motionState = "STOP";
if (speed >= 0.5) motionState = "FAST";
else if (speed >= 0.05) motionState = "SLOW";

stateData.trajectory.push({x: stateData.x, y: stateData.y});
if (stateData.trajectory.length > 200) stateData.trajectory.shift();

context.set("stateData", stateData);

msg.payload = {
    ax: ax,
    ay: ay,
    vx: stateData.vx,
    vy: stateData.vy,
    x: stateData.x,
    y: stateData.y,
    speed: speed,
    state: motionState,
    trajectory: stateData.trajectory
};

return msg;

context.set("stateData", {
    x: 0,
    y: 0,
    vx: 0,
    vy: 0,
    lastTime: Date.now(),
    trajectory: []
});
msg.payload = {
    ax: 0,
    ay: 0,
    vx: 0,
    vy: 0,
    x: 0,
    y: 0,
    speed: 0,
    state: "RESET",
    trajectory: []
};
return msg;
